using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable to run this agent.");
    return 1;
}

var topic = args.Length > 0
    ? string.Join(' ', args)
    : "recent advances in fusion energy";

Console.WriteLine($"🔍 Research Agent — topic: \"{topic}\"\n");

// ---------------------------------------------------------------------------
// Tools the agent can call
// ---------------------------------------------------------------------------
var notebook = new Notebook();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.ReadNotes),
};

// ---------------------------------------------------------------------------
// Build the chat client with automatic function-calling support
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

// ---------------------------------------------------------------------------
// Agent system prompt
// ---------------------------------------------------------------------------
var systemPrompt = $"""
    You are a research agent. Your goal is to research the following topic
    thoroughly and produce a clear, well-structured summary.

    Topic: {topic}

    You have access to the following tools:
    1. **WebSearch** — search the web for information. Call it multiple times
       with different queries to gather broad coverage.
    2. **SaveNote** — save an important finding so you can reference it later.
    3. **ReadNotes** — read back all the notes you have saved so far.

    Strategy:
    - Start by searching for the topic with 2-3 different queries.
    - Save the most important facts and findings as notes.
    - After gathering enough information, read your notes and produce a final
      summary that is clear, factual, and well-organized.
    - End your final message with "## Summary" followed by the consolidated
      findings.
    """;

// ---------------------------------------------------------------------------
// Run the agent loop
// ---------------------------------------------------------------------------
List<ChatMessage> history =
[
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User,
        $"Please research \"{topic}\" using your tools and then provide a summary."),
];

const int maxTurns = 10;
for (var turn = 0; turn < maxTurns; turn++)
{
    var response = await client.GetResponseAsync(history, chatOptions);

    // Append all response messages to history for the next turn.
    foreach (var msg in response.Messages)
        history.Add(msg);

    // Print any assistant text to the console.
    var assistantText = string.Concat(
        response.Messages
            .Where(m => m.Role == ChatRole.Assistant)
            .SelectMany(m => m.Contents.OfType<TextContent>())
            .Select(tc => tc.Text));

    if (!string.IsNullOrWhiteSpace(assistantText))
        Console.WriteLine(assistantText);

    // If the model didn't make any tool calls this turn, we're done.
    var madeToolCalls = response.Messages
        .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

    if (!madeToolCalls)
        break;
}

Console.WriteLine("\n✅ Research complete.");
return 0;

// ===========================================================================
// Tool implementations
// ===========================================================================

/// <summary>
/// Searches the web for the given query and returns a JSON array of results.
/// Each result has a title, url, and snippet.
/// </summary>
[Description("Search the web for information on a query. Returns a JSON array of results with title, url, and snippet.")]
static async Task<string> WebSearch(
    [Description("The search query string")] string query)
{
    Console.WriteLine($"  🌐 WebSearch(\"{query}\")");

    // Use the free DuckDuckGo HTML endpoint — no API key required.
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";

    try
    {
        var html = await http.GetStringAsync(url);
        var results = ParseDuckDuckGoResults(html, maxResults: 5);
        return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
    }
    catch (Exception ex)
    {
        return JsonSerializer.Serialize(new { error = ex.Message });
    }
}

/// <summary>Crude HTML scraper for DuckDuckGo HTML results.</summary>
static List<Dictionary<string, string>> ParseDuckDuckGoResults(string html, int maxResults)
{
    var results = new List<Dictionary<string, string>>();
    var span = html.AsSpan();

    // Each result lives inside <div class="result ..."> ... </div>
    // The title/link is in <a class="result__a" href="...">Title</a>
    // The snippet is in <a class="result__snippet" ...>Snippet</a>
    const string resultAnchor = "class=\"result__a\"";
    const string snippetAnchor = "class=\"result__snippet\"";

    var pos = 0;
    while (results.Count < maxResults)
    {
        var anchorIdx = html.IndexOf(resultAnchor, pos, StringComparison.Ordinal);
        if (anchorIdx < 0) break;

        // Extract href
        var hrefStart = html.LastIndexOf("href=\"", anchorIdx, StringComparison.Ordinal);
        var linkUrl = "";
        if (hrefStart >= 0)
        {
            hrefStart += 6;
            var hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd > hrefStart)
                linkUrl = WebUtility.HtmlDecode(html[hrefStart..hrefEnd]);
        }

        // Extract title text (between > and </a>)
        var titleStart = html.IndexOf('>', anchorIdx) + 1;
        var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.Ordinal);
        var title = titleEnd > titleStart
            ? StripHtml(html[titleStart..titleEnd])
            : "";

        // Extract snippet
        var snippet = "";
        var snippetIdx = html.IndexOf(snippetAnchor, titleEnd > 0 ? titleEnd : anchorIdx, StringComparison.Ordinal);
        if (snippetIdx >= 0 && snippetIdx - anchorIdx < 3000)
        {
            var snipStart = html.IndexOf('>', snippetIdx) + 1;
            var snipEnd = html.IndexOf("</a>", snipStart, StringComparison.Ordinal);
            if (snipEnd > snipStart)
                snippet = StripHtml(html[snipStart..snipEnd]);
        }

        if (!string.IsNullOrWhiteSpace(title))
        {
            results.Add(new Dictionary<string, string>
            {
                ["title"]   = title.Trim(),
                ["url"]     = linkUrl.Trim(),
                ["snippet"] = snippet.Trim(),
            });
        }

        pos = anchorIdx + resultAnchor.Length;
    }

    return results;
}

static string StripHtml(string html)
{
    // Remove tags and decode entities.
    var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
    return WebUtility.HtmlDecode(text).Trim();
}

// ===========================================================================
// Notebook — simple in-memory note-taking tool
// ===========================================================================

sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save an important research finding as a note. Returns confirmation.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 SaveNote (#{_notes.Count}): {Truncate(note, 80)}");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Read all notes saved so far. Returns the full list.")]
    public string ReadNotes()
    {
        Console.WriteLine($"  📖 ReadNotes ({_notes.Count} notes)");
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join('\n', _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }

    private static string Truncate(string s, int max) =>
        s.Length <= max ? s : string.Concat(s.AsSpan(0, max), "…");
}

