 using System.ComponentModel;
 using System.Net;
 using System.Text.Json;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // ---------------------------------------------------------------------------
 // Configuration
 // ---------------------------------------------------------------------------
 var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
 var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

 if (string.IsNullOrWhiteSpace(apiKey))
 {
     Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable to run this agent.");
     return 1;
 }

 var topic = args.Length > 0
     ? string.Join(' ', args)
     : "recent advances in fusion energy";

 Console.WriteLine($"🔍 Research Agent — topic: \"{topic}\"\n");

 // ---------------------------------------------------------------------------
 // Tools the agent can call
 // ---------------------------------------------------------------------------
 var notebook = new Notebook();

 var tools = new AIFunction[]
 {
     AIFunctionFactory.Create(WebSearch),
     AIFunctionFactory.Create(notebook.SaveNote),
     AIFunctionFactory.Create(notebook.ReadNotes),
 };

 // ---------------------------------------------------------------------------
 // Build the chat client with automatic function-calling support
 // ---------------------------------------------------------------------------
 IChatClient client = new OpenAIClient(apiKey)
     .GetChatClient(model)
     .AsIChatClient()
     .AsBuilder()
     .UseFunctionInvocation()
     .Build();

 var chatOptions = new ChatOptions { Tools = [.. tools] };

 // ---------------------------------------------------------------------------
 // Agent system prompt
 // ---------------------------------------------------------------------------
 var systemPrompt = $"""
     You are a research agent. Your goal is to research the following topic
     thoroughly and produce a clear, well-structured summary.

     Topic: {topic}

     You have access to the following tools:
     1. **WebSearch** — search the web for information. Call it multiple times
        with different queries to gather broad coverage.
     2. **SaveNote** — save an important finding so you can reference it later.
     3. **ReadNotes** — read back all the notes you have saved so far.

     Strategy:
     - Start by searching for the topic with 2-3 different queries.
     - Save the most important facts and findings as notes.
     - After gathering enough information, read your notes and produce a final
       summary that is clear, factual, and well-organized.
     - End your final message with "## Summary" followed by the consolidated
       findings.
     """;

 // ---------------------------------------------------------------------------
 // Run the agent loop
 // ---------------------------------------------------------------------------
 List<ChatMessage> history =
 [
     new(ChatRole.System, systemPrompt),
     new(ChatRole.User,
         $"Please research \"{topic}\" using your tools and then provide a summary."),
 ];

 const int maxTurns = 10;
 for (var turn = 0; turn < maxTurns; turn++)
 {
     var response = await client.GetResponseAsync(history, chatOptions);

     // Append all response messages to history for the next turn.
     foreach (var msg in response.Messages)
         history.Add(msg);

     // Print any assistant text to the console.
     var assistantText = string.Concat(
         response.Messages
             .Where(m => m.Role == ChatRole.Assistant)
             .SelectMany(m => m.Contents.OfType<TextContent>())
             .Select(tc => tc.Text));

     if (!string.IsNullOrWhiteSpace(assistantText))
         Console.WriteLine(assistantText);

     // If the model didn't make any tool calls this turn, we're done.
     var madeToolCalls = response.Messages
         .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

     if (!madeToolCalls)
         break;
 }

 Console.WriteLine("\n✅ Research complete.");
 return 0;

